     1	using InventoryFlow.Application.Features.Authentication;
     2	using InventoryFlow.Domain.Entities;
     3	using InventoryFlow.Infrastructure.Identity;
     4	using InventoryFlow.Infrastructure.Persistence;
     5	using Microsoft.AspNetCore.Identity;
     6	using Microsoft.EntityFrameworkCore;
     7	using Microsoft.Extensions.Options;
     8	using System.Data;
     9	
    10	namespace InventoryFlow.Infrastructure.Authentication;
    11	
    12	/// <summary>Implements identity, session issuance, and refresh rotation.</summary>
    13	public sealed class IdentityAuthenticationService(
    14	    UserManager<ApplicationUser> userManager,
    15	    SignInManager<ApplicationUser> signInManager,
    16	    ApplicationDbContext dbContext,
    17	    JwtAccessTokenIssuer accessTokenIssuer,
    18	    RefreshTokenGenerator refreshTokenGenerator,
    19	    IOptions<JwtOptions> options,
    20	    TimeProvider timeProvider) : IAuthenticationService
    21	{
    22	    private readonly JwtOptions _options = options.Value;
    23	
    24	    /// <inheritdoc />
    25	    public async Task<AuthenticationSession> RegisterAsync(RegisterUserCommand command, CancellationToken cancellationToken)
    26	    {
    27	        var user = new ApplicationUser { Id = Guid.NewGuid(), UserName = command.Email.Trim(), Email = command.Email.Trim(), DisplayName = command.DisplayName.Trim() };
    28	        var result = await userManager.CreateAsync(user, command.Password);
    29	        if (!result.Succeeded) throw new AuthenticationException();
    30	        return await IssueSessionAsync(user, Guid.NewGuid(), cancellationToken);
    31	    }
    32	
    33	    /// <inheritdoc />
    34	    public async Task<AuthenticationSession?> LoginAsync(LoginUserCommand command, CancellationToken cancellationToken)
    35	    {
    36	        var user = await userManager.FindByEmailAsync(command.Email.Trim());
    37	        if (user is null) return null;
    38	        var result = await signInManager.CheckPasswordSignInAsync(user, command.Password, lockoutOnFailure: true);
    39	        return result.Succeeded ? await IssueSessionAsync(user, Guid.NewGuid(), cancellationToken) : null;
    40	    }
    41	
    42	    /// <inheritdoc />
    43	    public async Task<AuthenticationSession?> RefreshAsync(string refreshToken, CancellationToken cancellationToken)
    44	    {
    45	        var now = timeProvider.GetUtcNow();
    46	        var hash = refreshTokenGenerator.Hash(refreshToken);
    47	        await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
    48	        var token = await dbContext.RefreshTokens.SingleOrDefaultAsync(item => item.TokenHash == hash, cancellationToken);
    49	        if (token is null) { await transaction.CommitAsync(cancellationToken); return null; }
    50	        if (!token.IsActive(now))
    51	        {
    52	            await RevokeFamilyAsync(token.FamilyId, now, cancellationToken);
    53	            await transaction.CommitAsync(cancellationToken);
    54	            return null;
    55	        }
    56	        token.Revoke(now);
    57	        var user = await userManager.FindByIdAsync(token.UserId.ToString());
    58	        if (user is null) { await dbContext.SaveChangesAsync(cancellationToken); await transaction.CommitAsync(cancellationToken); return null; }
    59	        var session = CreateSession(user, token.FamilyId, now);
    60	        dbContext.RefreshTokens.Add(session.Token);
    61	        await dbContext.SaveChangesAsync(cancellationToken);
    62	        await transaction.CommitAsync(cancellationToken);
    63	        return session.Session;
    64	    }
    65	
    66	    /// <inheritdoc />
    67	    public async Task LogoutAsync(string? refreshToken, CancellationToken cancellationToken)
    68	    {
    69	        if (string.IsNullOrWhiteSpace(refreshToken)) return;
    70	        var token = await dbContext.RefreshTokens.SingleOrDefaultAsync(item => item.TokenHash == refreshTokenGenerator.Hash(refreshToken), cancellationToken);
    71	        if (token is null) return;
    72	        await RevokeFamilyAsync(token.FamilyId, timeProvider.GetUtcNow(), cancellationToken);
    73	        await dbContext.SaveChangesAsync(cancellationToken);
    74	    }
    75	
    76	    /// <inheritdoc />
    77	    public async Task<AuthenticatedUser?> GetUserAsync(Guid userId, CancellationToken cancellationToken)
    78	    {
    79	        var user = await userManager.FindByIdAsync(userId.ToString());
    80	        return user is null ? null : ToUser(user);
    81	    }
    82	
    83	    private async Task<AuthenticationSession> IssueSessionAsync(ApplicationUser user, Guid familyId, CancellationToken cancellationToken)
    84	    {
    85	        var created = CreateSession(user, familyId, timeProvider.GetUtcNow());
    86	        dbContext.RefreshTokens.Add(created.Token);
    87	        await dbContext.SaveChangesAsync(cancellationToken);
    88	        return created.Session;
    89	    }
    90	
    91	    private (AuthenticationSession Session, RefreshToken Token) CreateSession(ApplicationUser user, Guid familyId, DateTimeOffset now)
    92	    {
    93	        var refreshValue = refreshTokenGenerator.Create();
    94	        var token = new RefreshToken(Guid.NewGuid(), user.Id, familyId, refreshTokenGenerator.Hash(refreshValue), now.AddDays(_options.RefreshTokenLifetimeDays));
    95	        var access = accessTokenIssuer.Issue(ToUser(user));
    96	        return (new AuthenticationSession(new AuthenticationResponse(access.Token, access.ExpiresAtUtc, ToUser(user)), refreshValue), token);
    97	    }
    98	
    99	    private async Task RevokeFamilyAsync(Guid familyId, DateTimeOffset now, CancellationToken cancellationToken)
   100	    {
   101	        var activeTokens = await dbContext.RefreshTokens.Where(item => item.FamilyId == familyId && item.RevokedAtUtc == null && item.ExpiresAtUtc > now).ToListAsync(cancellationToken);
   102	        foreach (var token in activeTokens) token.Revoke(now);
   103	    }
   104	
   105	    private static AuthenticatedUser ToUser(ApplicationUser user) => new(user.Id, user.Email ?? string.Empty, user.DisplayName);
   106	}
     1	using System.ComponentModel.DataAnnotations;
