     3	namespace InventoryFlow.Infrastructure.Authentication;
     4	
     5	/// <summary>Contains JWT and refresh-session settings.</summary>
     6	public sealed class JwtOptions
     7	{
     8	    /// <summary>Configuration section name.</summary>
     9	    public const string SectionName = "Jwt";
    10	    /// <summary>Gets or sets the trusted token issuer.</summary>
    11	    [Required] public string Issuer { get; set; } = string.Empty;
    12	    /// <summary>Gets or sets the intended token audience.</summary>
    13	    [Required] public string Audience { get; set; } = string.Empty;
    14	    /// <summary>Gets or sets the secret signing key, supplied outside tracked configuration.</summary>
    15	    [Required, MinLength(32)] public string SigningKey { get; set; } = string.Empty;
    16	    /// <summary>Gets or sets access-token lifetime in minutes.</summary>
    17	    [Range(1, 60)] public int AccessTokenLifetimeMinutes { get; set; } = 10;
    18	    /// <summary>Gets or sets refresh-token lifetime in days.</summary>
    19	    [Range(1, 30)] public int RefreshTokenLifetimeDays { get; set; } = 7;
    20	    /// <summary>Gets or sets the browser refresh cookie name.</summary>
    21	    [Required] public string RefreshCookieName { get; set; } = "inventory_flow_refresh";
    22	}
     1	using System.IdentityModel.Tokens.Jwt;
     2	using System.Security.Claims;
     3	using System.Text;
     4	using InventoryFlow.Application.Features.Authentication;
     5	using Microsoft.Extensions.Options;
     6	using Microsoft.IdentityModel.Tokens;
     7	
     8	namespace InventoryFlow.Infrastructure.Authentication;
     9	
    10	/// <summary>Issues short-lived signed access tokens.</summary>
    11	public sealed class JwtAccessTokenIssuer(IOptions<JwtOptions> options, TimeProvider timeProvider)
    12	{
    13	    private readonly JwtOptions _options = options.Value;
    14	    /// <summary>Creates an access token for a user.</summary>
    15	    public (string Token, DateTimeOffset ExpiresAtUtc) Issue(AuthenticatedUser user)
    16	    {
    17	        var expiresAtUtc = timeProvider.GetUtcNow().AddMinutes(_options.AccessTokenLifetimeMinutes);
    18	        var credentials = new SigningCredentials(new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_options.SigningKey)), SecurityAlgorithms.HmacSha256);
    19	        var claims = new[] { new Claim(JwtRegisteredClaimNames.Sub, user.Id.ToString()), new Claim(ClaimTypes.NameIdentifier, user.Id.ToString()), new Claim(ClaimTypes.Email, user.Email), new Claim("display_name", user.DisplayName) };
    20	        var token = new JwtSecurityToken(_options.Issuer, _options.Audience, claims, notBefore: timeProvider.GetUtcNow().UtcDateTime, expires: expiresAtUtc.UtcDateTime, signingCredentials: credentials);
    21	        return (new JwtSecurityTokenHandler().WriteToken(token), expiresAtUtc);
    22	    }
    23	}
     1	using System.Security.Cryptography;
     2	
     3	namespace InventoryFlow.Infrastructure.Authentication;
     4	
     5	/// <summary>Generates opaque refresh values and their one-way hashes.</summary>
     6	public sealed class RefreshTokenGenerator
     7	{
     8	    /// <summary>Generates a 256-bit URL-safe opaque value.</summary>
     9	    public string Create() => Convert.ToBase64String(RandomNumberGenerator.GetBytes(32)).TrimEnd('=').Replace('+', '-').Replace('/', '_');
    10	    /// <summary>Hashes an opaque value for persistence.</summary>
    11	    public string Hash(string token) => Convert.ToHexString(SHA256.HashData(System.Text.Encoding.UTF8.GetBytes(token)));
    12	}
